+/// [ft-nk6u9] Is this byte a C1 string introducer (the char after ESC
+/// that opens OSC / DCS / SOS / PM / APC)?
+#[inline]
+pub(crate) fn is_string_intro_byte(b: u8) -> bool {
+    // 0x50 = 'P' (DCS), 0x58 = 'X' (SOS), 0x5D = ']' (OSC),
+    // 0x5E = '^' (PM), 0x5F = '_' (APC).
+    matches!(b, 0x50 | 0x58 | 0x5D | 0x5E | 0x5F)
+}
